document.addEventListener("click",e=>{const t=e.target.closest(".avatar-link");if(!t||e.defaultPrevented||e.button!==0||e.metaKey||e.ctrlKey||e.shiftKey||e.altKey||t.classList.contains("avatar-link--departing"))return;e.preventDefault();t.classList.add("avatar-link--departing");t.setAttribute("aria-disabled","true");setTimeout(()=>location.assign(t.href),500)});addEventListener("pageshow",()=>document.querySelectorAll(".avatar-link--departing").forEach(e=>{e.classList.remove("avatar-link--departing");e.removeAttribute("aria-disabled")}));
